async function insertQuestions() {
  console.log(`Inserting ${newQuestions.length} questions...`);
  
  const batchSize = 50;
  let inserted = 0;
  
  for (let i = 0; i < newQuestions.length; i += batchSize) {
    const batch = newQuestions.slice(i, i + batchSize);
    const { error } = await supabase
      .from('questions')
      .upsert(batch, { onConflict: 'id' });
    
    if (error) {
      console.error(`Error at batch ${i}-${i + batchSize}:`, error.message);
      process.exit(1);
    }
    inserted += batch.length;
    console.log(`  Inserted ${inserted}/${newQuestions.length}...`);
  }
  
  console.log('\nVerifying...');
  const { data, error } = await supabase
    .from('questions')
    .select('category, id')
    .order('id');
  
  if (error) { console.error('Verify error:', error.message); return; }
  
  const counts = {};
  for (const row of data) counts[row.category] = (counts[row.category] || 0) + 1;
  
  console.log(`\nTotal questions: ${data.length}`);
  console.log('Per category:');
  for (const [cat, count] of Object.entries(counts).sort()) {
    console.log(`  ${cat}: ${count}`);
  }
}

insertQuestions().catch(console.error);

